-- Migration 020 - SRH Washed one-time import
--
-- One-time import of Cafe Granja la Esperanza Sudan Rume Hybrid Washed
-- (lot_id = 'CGLE-SRUME-WASHED-2026') for the self-roasted-flow audit
-- sprint. This is a deliberate exception to the upload-on-resolution
-- workflow rule - the bean is structurally complete (#133 declared as
-- reference roast, #148 as closest replication) and provides realistic
-- shape for auditing /green/[id].
--
-- Idempotent:
--   * green_beans: ON CONFLICT (user_id, lot_id) DO NOTHING
--   * roasts: ON CONFLICT (user_id, green_bean_id, batch_id) DO NOTHING
--   * experiments: ON CONFLICT (user_id, green_bean_id, experiment_id) DO NOTHING
--   * cuppings: ON CONFLICT (user_id, roast_id, cupping_date, eval_method) DO NOTHING
--     (new unique constraint added below)
--   * roast_learnings: ON CONFLICT (user_id, green_bean_id) DO NOTHING
--
-- Canonical decisions (full rationale: plans/noble-waddling-porcupine.md):
--   * producer: 'Café Granja La Esperanza' -> 'Cafe Granja la Esperanza' (producer-registry)
--   * variety: 'SUDÁN RUMÉ' -> 'Sudan Rume' (cultivar registry)
--   * origin: 'Columbia' typo -> 'Colombia'
--   * process: 'Hybrid Washed' verbatim (falls into Other family - flagged in audit)
--   * best_batch_id: '#133 (confirmed), #148 (replication)' -> '133' (UI does
--     strict string equality; multi-value unsupported - flagged in audit)
--   * terroir_id: reuses existing Colombia/Valle del Cauca/Western Andean
--     Cordillera row (meso='Trujillo highlands' is wrong for Caicedonia -
--     flagged in audit). terroirs table has unique(country, admin_region,
--     macro_terroir) so a new row would violate.
--   * cuppings.sweetness + cuppings.brew_method dropped at import (schema
--     gap; brew_method folded into eval_method to preserve).

BEGIN;

-- =====================================================================
-- Schema: unique constraint to enable cuppings idempotency
-- =====================================================================
ALTER TABLE cuppings
  ADD CONSTRAINT cuppings_user_roast_date_method_unique
  UNIQUE (user_id, roast_id, cupping_date, eval_method);

-- =====================================================================
-- Green bean row
-- =====================================================================
INSERT INTO green_beans (
  user_id, lot_id, name, producer, origin, region, variety, process, importer,
  source_type, link, purchase_date, price_per_kg, quantity_g, moisture, density,
  terroir_id, cultivar_id
)
SELECT
  (SELECT id FROM profiles LIMIT 1),
  'CGLE-SRUME-WASHED-2026', 'CGLE - Sudan Rume Hybrid Washed', 'Cafe Granja la Esperanza', 'Colombia', 'Valle del Cauca - Caicedonia - Las Margaritas', 'Sudan Rume', 'Hybrid Washed', 'Café Granja La Esperanza', 'Farm Direct', 'https://cafegranjalaesperanza.com/products/sudan-rume-hybrid-washed', '2026-02-18', 200.62, 2268, '10.0%', '809 g/L',
  (SELECT id FROM terroirs WHERE country = 'Colombia' AND admin_region = 'Valle del Cauca' AND macro_terroir = 'Western Andean Cordillera' LIMIT 1),
  (SELECT id FROM cultivars WHERE cultivar_name = 'Sudan Rume' LIMIT 1)
ON CONFLICT (user_id, lot_id) DO NOTHING;

-- =====================================================================
-- Roasts (17 rows)
-- =====================================================================
WITH bean AS (SELECT id AS green_bean_id, user_id FROM green_beans WHERE lot_id = 'CGLE-SRUME-WASHED-2026')
INSERT INTO roasts (
  user_id, green_bean_id,
  batch_id, roast_date, coffee_name, profile_link, batch_size_g, roasted_weight_g,
  weight_loss_pct, agtron, color_description, yellowing_time, fc_start, fc_temp,
  drop_time, drop_temp, dev_time_s, dev_ratio, what_worked, what_didnt,
  what_to_change, worth_repeating, is_reference
)
SELECT
  bean.user_id, bean.green_bean_id,
  rec.batch_id, rec.roast_date::date, rec.coffee_name, rec.profile_link,
  rec.batch_size_g, rec.roasted_weight_g, rec.weight_loss_pct, rec.agtron,
  rec.color_description, rec.yellowing_time, rec.fc_start, rec.fc_temp,
  rec.drop_time, rec.drop_temp, rec.dev_time_s, rec.dev_ratio,
  rec.what_worked, rec.what_didnt, rec.what_to_change,
  rec.worth_repeating, rec.is_reference
FROM bean,
  jsonb_to_recordset('[{"batch_id": "104", "roast_date": "2026-03-20", "coffee_name": "CGLE - Sudan Rume Hybrid Washed", "profile_link": "https://connect.roestcoffee.com/machine/godly/logs/3579758/", "batch_size_g": 100, "roasted_weight_g": 90, "weight_loss_pct": 9.6, "agtron": 78.6, "color_description": "Light", "yellowing_time": "1:53", "fc_start": "3:33", "fc_temp": 205.8, "drop_time": "4:03", "drop_temp": 211.0, "dev_time_s": 30, "dev_ratio": "12.3%", "what_worked": "Clean structure, fast and tidy roast shape, good clarity bias, no obvious crash/flick issues", "what_didnt": "Slightly underdeveloped overall, likely a bit hollow or top-heavy, development too short", "what_to_change": "Add a little more momentum into first crack and extend development slightly, without materially increasing end temperature", "worth_repeating": false, "is_reference": false}, {"batch_id": "106", "roast_date": "2026-03-20", "coffee_name": "CGLE - Sudan Rume Hybrid Washed", "profile_link": "https://connect.roestcoffee.com/machine/godly/logs/3579770/", "batch_size_g": 100, "roasted_weight_g": 89, "weight_loss_pct": 10.100000000000001, "agtron": 74.6, "color_description": "Light", "yellowing_time": "1:53", "fc_start": "3:38", "fc_temp": 207.3, "drop_time": "4:13", "drop_temp": 212.6, "dev_time_s": 35, "dev_ratio": "13.8%", "what_worked": "More complete than #104, better internal development, still clean and light, strongest candidate for a starting benchmark", "what_didnt": "First crack still a bit late and hot, finish likely relying slightly too much on end temp rather than phase balance", "what_to_change": "Keep similar development but carry a touch more heat into FC so it lands earlier, then drop slightly cooler", "worth_repeating": true, "is_reference": false}, {"batch_id": "108", "roast_date": "2026-03-20", "coffee_name": "CGLE - Sudan Rume Hybrid Washed", "profile_link": "https://connect.roestcoffee.com/machine/godly/logs/3579786/", "batch_size_g": 100, "roasted_weight_g": 89, "weight_loss_pct": 10.6, "agtron": 71.0, "color_description": "Light", "yellowing_time": "1:52", "fc_start": "3:43", "fc_temp": 209.0, "drop_time": "4:18", "drop_temp": 214.6, "dev_time_s": 35, "dev_ratio": "13.6%", "what_worked": "More developed and likely sweeter than #104, still orderly and technically controlled", "what_didnt": "Pushed too far for this coffee, FC too late/hot, drop temp likely suppresses florals and clarity, risk of more tea/roast structure", "what_to_change": "Pull the profile back slightly from this point, especially end temp, and get FC earlier rather than finishing hotter", "worth_repeating": false, "is_reference": false}, {"batch_id": "109", "roast_date": "2026-03-22", "coffee_name": "CGLE - Sudan Rume Hybrid Washed", "profile_link": "https://connect.roestcoffee.com/machine/godly/logs/3581910/", "batch_size_g": 100, "roasted_weight_g": 90, "weight_loss_pct": 9.8, "agtron": 75.5, "color_description": "Light", "yellowing_time": "2:05", "fc_start": "3:57", "fc_temp": 202.9, "drop_time": "4:37", "drop_temp": 209.3, "dev_time_s": 40, "dev_ratio": "14.4%", "what_worked": "Much more controlled approach to FC, smoother RoR, better phase balance, less aggressive surface development", "what_didnt": "Still slightly conservative finish, may leave some sweetness on table", "what_to_change": "Slightly extend dev OR carry a touch more energy into late Maillard to avoid needing longer dev", "worth_repeating": true, "is_reference": false}, {"batch_id": "110", "roast_date": "2026-03-22", "coffee_name": "CGLE - Sudan Rume Hybrid Washed", "profile_link": "https://connect.roestcoffee.com/machine/godly/logs/3581918/", "batch_size_g": 100, "roasted_weight_g": 90, "weight_loss_pct": 9.9, "agtron": 74.4, "color_description": "Light", "yellowing_time": "2:04", "fc_start": "4:10", "fc_temp": 205.8, "drop_time": "4:40", "drop_temp": 209.7, "dev_time_s": 30, "dev_ratio": "10.7%", "what_worked": "Very clean, controlled roast, strong clarity, decisive FC event", "what_didnt": "Development likely too short for this system, risk of slight hollowness or lack of mid-palate", "what_to_change": "Increase dev back toward ~35–40 sec without increasing drop temp much", "worth_repeating": false, "is_reference": false}, {"batch_id": "111", "roast_date": "2026-03-22", "coffee_name": "CGLE - Sudan Rume Hybrid Washed", "profile_link": "https://connect.roestcoffee.com/machine/godly/logs/3581921/", "batch_size_g": 100, "roasted_weight_g": 89, "weight_loss_pct": 10.5, "agtron": 72.0, "color_description": "Light", "yellowing_time": "2:05", "fc_start": "4:19", "fc_temp": 207.0, "drop_time": "4:50", "drop_temp": 210.7, "dev_time_s": 31, "dev_ratio": "10.7%", "what_worked": "Strongest internal development signal, best structural setup, good heat penetration, controlled but complete", "what_didnt": "FC slightly late, still slightly reliant on end-of-roast push", "what_to_change": "Bring FC slightly earlier rather than extending roast further", "worth_repeating": true, "is_reference": false}, {"batch_id": "112", "roast_date": "2026-03-23", "coffee_name": "CGLE - Sudan Rume Hybrid Washed", "profile_link": "https://connect.roestcoffee.com/machine/godly/logs/3585442", "batch_size_g": 100, "roasted_weight_g": 90, "weight_loss_pct": 9.1, "agtron": 76.3, "color_description": "Light", "yellowing_time": "2:04", "fc_start": "4:05", "fc_temp": 205.4, "drop_time": "4:35", "drop_temp": 209.2, "dev_time_s": 30, "dev_ratio": "10.9%", "what_worked": "Much lower FC temp vs prior sets, cleaner heat progression, strong control, likely improved clarity and less roast influence", "what_didnt": "Dev too short for this system, risk of returning to hollow / underdeveloped core", "what_to_change": "Extend dev slightly (35–40s) while keeping same FC timing", "worth_repeating": true, "is_reference": false}, {"batch_id": "113", "roast_date": "2026-03-23", "coffee_name": "CGLE - Sudan Rume Hybrid Washed", "profile_link": "https://connect.roestcoffee.com/machine/godly/logs/3585448", "batch_size_g": 100, "roasted_weight_g": 90, "weight_loss_pct": 9.1, "agtron": 72.0, "color_description": "Light", "yellowing_time": "2:04", "fc_start": "4:10", "fc_temp": 206.3, "drop_time": "4:36", "drop_temp": 209.3, "dev_time_s": 26, "dev_ratio": "9.4%", "what_worked": "Very clean profile, controlled FC entry, minimal roast imprint", "what_didnt": "Dev too short, high risk of underdevelopment and thin body", "what_to_change": "Increase dev materially (this is below viable floor for this coffee)", "worth_repeating": false, "is_reference": false}, {"batch_id": "114", "roast_date": "2026-03-23", "coffee_name": "CGLE - Sudan Rume Hybrid Washed", "profile_link": "https://connect.roestcoffee.com/machine/godly/logs/3585463", "batch_size_g": 100, "roasted_weight_g": 90, "weight_loss_pct": 10.0, "agtron": 71.1, "color_description": "Light", "yellowing_time": "2:02", "fc_start": "4:20", "fc_temp": 205.1, "drop_time": "4:50", "drop_temp": 206.3, "dev_time_s": 30, "dev_ratio": "10.3%", "what_worked": "Strong internal development setup, lower drop temp, better phase balance vs earlier sets", "what_didnt": "FC slightly late, energy may be slightly insufficient pre-FC", "what_to_change": "Bring FC slightly earlier (~4:05–4:10) while holding same drop temp", "worth_repeating": true, "is_reference": false}, {"batch_id": "115", "roast_date": "2026-03-23", "coffee_name": "CGLE - Sudan Rume Hybrid Washed", "profile_link": "https://connect.roestcoffee.com/machine/godly/logs/3585476", "batch_size_g": 100, "roasted_weight_g": 90, "weight_loss_pct": 9.4, "agtron": 73.3, "color_description": "Light", "yellowing_time": "2:02", "fc_start": "4:04", "fc_temp": 203.5, "drop_time": "4:39", "drop_temp": 206.0, "dev_time_s": 35, "dev_ratio": "12.5%", "what_worked": "Best FC positioning so far, lowest FC temp, proper dev window, strong candidate for balanced structure", "what_didnt": "Possibly still slightly conservative on dev depending on cup outcome", "what_to_change": "Test slightly longer dev (40–45s) without increasing drop temp", "worth_repeating": true, "is_reference": true}, {"batch_id": "118", "roast_date": "2026-03-26", "coffee_name": "CGLE Sudan Rume Hybrid Washed", "profile_link": "https://connect.roestcoffee.com/machine/godly/logs/3595323", "batch_size_g": 100, "roasted_weight_g": 89, "weight_loss_pct": 10.2, "agtron": 66.9, "color_description": "Medium-light", "yellowing_time": "2:01", "fc_start": "4:20", "fc_temp": 205.4, "drop_time": "5:00", "drop_temp": 207.0, "dev_time_s": 40, "dev_ratio": "13.3%", "what_worked": "DTR% reasonable at 13.3%; weight loss good", "what_didnt": "Agtron 66.9 too dark; FC too late and too hot; TP still 78.4°C despite new BBP; Maillard bloated to 46.3%; total time at ceiling of window", "what_to_change": "Higher charge temp; investigate TP root cause", "worth_repeating": false, "is_reference": false}, {"batch_id": "119", "roast_date": "2026-03-26", "coffee_name": "CGLE Sudan Rume Hybrid Washed", "profile_link": "https://connect.roestcoffee.com/machine/godly/logs/3595328", "batch_size_g": 100, "roasted_weight_g": 90, "weight_loss_pct": 9.3, "agtron": 73.5, "color_description": "Light", "yellowing_time": "2:02", "fc_start": "4:12", "fc_temp": 204.5, "drop_time": "4:41", "drop_temp": 206.3, "dev_time_s": 29, "dev_ratio": "10.3%", "what_worked": "Drop temp 206.3°C excellent; Agtron 73.5 on target; total time 4:41 inside window", "what_didnt": "Dev time 29s/10.3% too short — below failure boundary; TP still 78.9°C", "what_to_change": "Extend dev time; TP still needs solving", "worth_repeating": false, "is_reference": false}, {"batch_id": "120", "roast_date": "2026-03-26", "coffee_name": "CGLE Sudan Rume Hybrid Washed", "profile_link": "https://connect.roestcoffee.com/machine/godly/logs/3595333", "batch_size_g": 100, "roasted_weight_g": 90, "weight_loss_pct": 9.4, "agtron": 71.0, "color_description": "Light", "yellowing_time": "2:02", "fc_start": "4:23", "fc_temp": 205.5, "drop_time": "4:48", "drop_temp": 206.4, "dev_time_s": 25, "dev_ratio": "8.7%", "what_worked": "Drop temp controlled; weight loss consistent", "what_didnt": "Dev 8.7% is below failure boundary; Maillard 49% — stall pattern; TP only 80.6°C despite highest charge (119.3°C) in session; FC arrived very late for the charge temp", "what_to_change": "Sequential roast drum heat building causing unpredictable behavior — this roast slot may be unreliable for diagnostics", "worth_repeating": false, "is_reference": false}, {"batch_id": "122", "roast_date": "2026-03-26", "coffee_name": "CGLE Sudan Rume Hybrid Washed", "profile_link": "https://connect.roestcoffee.com/machine/godly/logs/3595341", "batch_size_g": 100, "roasted_weight_g": 90, "weight_loss_pct": 9.6, "agtron": 77.8, "color_description": "Light", "yellowing_time": "2:01", "fc_start": "3:53", "fc_temp": 202.4, "drop_time": "4:38", "drop_temp": 206.7, "dev_time_s": 45, "dev_ratio": "16.2%", "what_worked": "Lowest FC temp in entire run (202.4°C); FC arriving earliest in session (3:53); DTR 16.2% highest in run; drop temp controlled at 206.7°C; total time 4:38 inside window; Maillard 40.3% closest to friend''s 39.1%", "what_didnt": "Agtron 77.8 lighter than target (73–74 would be ideal); TP still 78.4°C — BBP not solving this; 117°C charge driving earlier FC but mechanism not yet understood", "what_to_change": "Confirm 117°C charge is reproducible at session start; investigate TP independently; measure ground Agtron at Day 10 to check internal development", "worth_repeating": false, "is_reference": false}, {"batch_id": "133", "roast_date": "2026-04-03", "coffee_name": "CGLE Sudan Rume Hybrid Washed", "profile_link": "https://connect.roestcoffee.com/machine/godly/logs/3616101/", "batch_size_g": 100, "roasted_weight_g": 90, "weight_loss_pct": 9.5, "agtron": 77.5, "color_description": "Light", "yellowing_time": "165.4°C", "fc_start": "4:07", "fc_temp": 204.5, "drop_time": "4:41", "drop_temp": 206.9, "dev_time_s": 34, "dev_ratio": "12.1%", "what_worked": "Drop temp controlled; consistent with #119 behavior; confirms profile baseline", "what_didnt": "FC still at 204.5°C — no improvement over #119 despite slightly higher charge; Maillard still bloated at 44.8%", "what_to_change": "Load beans into hopper earlier (~125°C) to replicate #134''s thermal advantage", "worth_repeating": false, "is_reference": false}, {"batch_id": "134", "roast_date": "2026-04-03", "coffee_name": "CGLE Sudan Rume Hybrid Washed", "profile_link": "https://connect.roestcoffee.com/machine/godly/logs/3616106/", "batch_size_g": 100, "roasted_weight_g": 91, "weight_loss_pct": 8.7, "agtron": 80.1, "color_description": "Light — slightly lighter than target", "yellowing_time": "165.2°C", "fc_start": "3:32", "fc_temp": 197.6, "drop_time": "4:22", "drop_temp": 205.5, "dev_time_s": 50, "dev_ratio": "19.1%", "what_worked": "Lowest FC temp in entire run; Maillard phase closest to friend’s reference; drop temp excellent; most structurally interesting roast in V5", "what_didnt": "Agtron 80.1 lighter than ideal target; 19.1% DTR may be too high — pending cup result; hopper pre-load not yet a repeatable controlled variable", "what_to_change": "Standardize hopper pre-load timing; measure ground Agtron at Day 7 pourover; test whether DTR 19% is too high or correct for this coffee", "worth_repeating": false, "is_reference": false}, {"batch_id": "135", "roast_date": "2026-04-03", "coffee_name": "CGLE Sudan Rume Hybrid Washed", "profile_link": "https://connect.roestcoffee.com/machine/godly/logs/3616111/", "batch_size_g": 100, "roasted_weight_g": 89, "weight_loss_pct": 10.8, "agtron": 69.1, "color_description": "Medium-light — outside target", "yellowing_time": "165.3°C", "fc_start": "4:21", "fc_temp": 205.2, "drop_time": "5:11", "drop_temp": 206.7, "dev_time_s": 50, "dev_ratio": "16.1%", "what_worked": "Dev time extended as planned; drop temp controlled", "what_didnt": "Total time 5:11 over ceiling; Agtron 69.1 too dark; Maillard 44.7% bloated; sequential drum heat compounded 1:00 end condition", "what_to_change": "Drop 1:00 end condition from V6 — this is above the ceiling; do not repeat", "worth_repeating": false, "is_reference": false}]') AS rec(
    batch_id text, roast_date text, coffee_name text, profile_link text,
    batch_size_g integer, roasted_weight_g integer, weight_loss_pct numeric,
    agtron numeric, color_description text, yellowing_time text, fc_start text,
    fc_temp numeric, drop_time text, drop_temp numeric, dev_time_s integer,
    dev_ratio text, what_worked text, what_didnt text, what_to_change text,
    worth_repeating boolean, is_reference boolean
  )
ON CONFLICT (user_id, green_bean_id, batch_id) DO NOTHING;

-- =====================================================================
-- Experiments (6 rows)
-- =====================================================================
WITH bean AS (SELECT id AS green_bean_id, user_id FROM green_beans WHERE lot_id = 'CGLE-SRUME-WASHED-2026')
INSERT INTO experiments (
  user_id, green_bean_id,
  experiment_id, batch_ids, context, primary_question, control_baseline,
  shared_constants, variable_changed, levels_tested, expected_outcomes,
  failure_boundary, observed_outcome_a, observed_outcome_b, observed_outcome_c,
  observed_outcome_d, winner, key_insight, what_changes_going_forward
)
SELECT
  bean.user_id, bean.green_bean_id,
  rec.experiment_id, rec.batch_ids, rec.context, rec.primary_question, rec.control_baseline,
  rec.shared_constants, rec.variable_changed, rec.levels_tested, rec.expected_outcomes,
  rec.failure_boundary, rec.observed_outcome_a, rec.observed_outcome_b, rec.observed_outcome_c,
  rec.observed_outcome_d, rec.winner, rec.key_insight, rec.what_changes_going_forward
FROM bean,
  jsonb_to_recordset('[{"experiment_id": "SRUME-WASHED-COUNTERFLOW-01", "batch_ids": "104, 106, 108", "context": "First roast set for this coffee in counterflow. Goal was to establish an initial benchmark and understand how much development this dense, low-moisture washed Sudan Rume wants before losing clarity. All three batches roasted on V1 \"Counterflow\" profile, charge ~108–109°C, drop 211–214.6°C.", "primary_question": "What starting roast structure gives the best balance of clarity, sweetness, and internal development for this coffee on the Roest in counterflow?", "control_baseline": "None — first roast set for this coffee", "shared_constants": "100g batch, Roest L200 Ultra, counterflow, fan ~90%, RPM 65, charge ~108–109°C, same general profile family", "variable_changed": "Degree of development through late-phase energy and finish level", "levels_tested": "A=#104: 30s dev, drop 211°C, Agtron 78.6 / B=#106: 35s dev, drop 212.6°C, Agtron 74.6 / C=#108: 35s dev, drop 214.6°C, Agtron 71", "expected_outcomes": "A: maximum clarity, risk of underdevelopment and hollow cup. B: improved sweetness and integration while staying light and clean. C: more sweetness and body, risk of muting florals and adding roast/tea structure.", "failure_boundary": "Underdevelopment: hollow acidity, nutty/cereal character, thin body, disconnected acidity. Overdevelopment: muted top notes, tea dryness, loss of washed-coffee clarity, roasty finish.", "observed_outcome_a": "Day 4 cupping only — very expressive aromatics, high sweetness, fruit-driven. Hollow body, disconnected acidity. Strong spoon but loses appeal in full cup sip. Not advanced to pourover.", "observed_outcome_b": "Day 4: more complete than #104, brighter, slightly better integrated, still lightly hollow, less expressive in full sip. Day 9 pourover: clear winner. Bright, sharp attack with sour-tropical fruit quality. Sweetness present (syrupy noted by second taster). Black tea body. Drying/oversteep finish present but manageable. Opens meaningfully as it cools — tropical fruit emerges, blends together. Full cup significantly more expressive than spoon. Ground Agtron 74.", "observed_outcome_c": "Day 4: most integrated of V1 set, best body, flattest aromatics. Drinkable but trades distinctiveness for integration. Day 9 pourover: body-centric, darker, heavier, less expressive at every stage. Orange rind, pronounced bitterness and drying. No real attack. Does not open as it cools. Ground Agtron 70.8.", "observed_outcome_d": null, "winner": "#106 — clear preference at Day 9 pourover", "key_insight": "Higher drop temp (214.6°C on #108) produced integration on the cupping table at Day 4 but resulted in a darker, heavier, less expressive pourover at Day 9 — the opposite of what was wanted. #106''s drop at 212.6°C preserved more expressiveness and brightness. However, both batches show drying/oversteep finish and sour-fermented fruit quality that is unexpected in a washed coffee — likely indicating that drop temps across the whole V1 set (211–214.6°C) are still too high and that internal development is incomplete despite the surface structure. The spoon-to-cup gap narrowing positively for #106 suggests the pourover brew method better resolves this coffee''s character than the cupping table.", "what_changes_going_forward": "V1 confirmed: stop solving structure with higher drop temps. The winning expression in this coffee comes from preserving brightness and expressiveness, not adding body through higher end temps. V2 and beyond should target lower drop temps (sub-210°C, ideally 205–207°C), earlier FC timing, and better mid-phase heat penetration to address the hollow/disconnected acidity without pushing end temp. The drying/oversteep finish and sour fruit quality are residual signals of insufficient internal development — the fix is profile shape, not dev time extension at high temperature."}, {"experiment_id": "SRUME-WASHED-COUNTERFLOW-02", "batch_ids": "109, 110, 111", "context": "Second iteration after fixing heat transfer imbalance. New system reduces airflow and redistributes energy into mid-phase. Tested development time response under a more controlled and internally focused roast environment. #110 and #111 advanced to Day 10 pourover (April 1).", "primary_question": "Within the improved heat transfer system, how should development time be adjusted when first crack becomes more vigorous and internally driven?", "control_baseline": "Batch #106 (best V1 roast)", "shared_constants": "100g batch, Roest L200 Ultra, counterflow, RPM 65, updated inlet (~235→247°C), airflow (80→65→72→75%), same coffee", "variable_changed": "Development time under improved heat transfer conditions", "levels_tested": "A=#109: 40s dev (14.4%) / B=#110: 30s dev (10.7%) / C=#111: 31s dev (10.7%) with more heat carry into late roast", "expected_outcomes": "A: balanced, slightly conservative, structured but possibly not fully expressive. B: highest clarity, risk of underdevelopment due to short dev. C: improved structure and sweetness due to better heat carry, even with shorter dev.", "failure_boundary": "Underdevelopment: hollow, thin, cereal notes. Overdevelopment: muted florals, tea-like, loss of clarity.", "observed_outcome_a": "Day 4: controlled and clean; expressive aromatics and brightness on spoon; significant spoon-to-cup gap — disconnected acidity turns sour in full sip; never fully integrates. Pourover not completed.", "observed_outcome_b": "Day 4: most complete and integrated; fuller aroma; lime acidity; loses expressiveness in full sip; trending monotone. Day 10 pourover: interesting spice and cardamom character on hot spoon; mellows and flattens at cool stage; lactic/cheese-like defect emerges in full cup sip and dominates finish — undermines the expression entirely. Ground Agtron 70.8 (medium-light). Not preferred in full cup.", "observed_outcome_c": "Day 4: flat throughout — no acidity, sweetness, or roast character; underdeveloped smell; not expressive or integrated. Day 10 pourover: complete reversal from Day 4 assessment. More pungent spice on hot spoon than #110; mellows more gracefully; full cup reveals vanilla, light tea, tropical fruit (raspberry), clean finish, smooth body. No lactic defect. Preferred in full cup at cool stage. Ground Agtron 73.5 (light).", "observed_outcome_d": null, "winner": "#111 — reverses Day 4 assessment. Full cup pourover is the decision gate and #111 wins clearly.", "key_insight": "Day 4 cupping vs Day 10 pourover reversal was confirmed again. #110 looked like the winner at Day 4 and developed a lactic/cheese defect at Day 10 pourover; #111 looked flat at Day 4 and revealed a clean, smooth, vanilla-fruit expression at Day 10. The Day 10 pourover gate is mandatory for this coffee. Ground Agtron deltas also support #111 as more even in development than #110.", "what_changes_going_forward": "Day 4 cupping on this coffee should be treated as directional only — do not eliminate batches based on Day 4 alone. Lactic/cheese defect at Day 10 pourover is a confirmed elimination signal. V3 confirmed the correct direction: lower drop temps and earlier FC. V5 design stands as planned."}, {"experiment_id": "SRUME-WASHED-COUNTERFLOW-03", "batch_ids": "112, 113, 114, 115", "context": "Third iteration after redesigning airflow and inlet strategy. Explored lower drop temperatures (targeting 206°C vs. 209–214°C in V1/V2) and earlier FC positioning while varying development time to find structural balance. Both #114 and #115 advanced to Day 8 pourover.", "primary_question": "With improved heat penetration and earlier FC, what development time range produces the best balance of clarity, structure, and expression?", "control_baseline": "Batch #106 (best V1 roast)", "shared_constants": "100g batch, Roest L200 Ultra, counterflow, RPM 65, reduced airflow (~80→65→70+%), flatter inlet peak (~245–248°C), charge ~111–113°C, same coffee", "variable_changed": "Development time and FC timing interaction", "levels_tested": "A=#112: 30s dev, FC 4:05/205.4°C, drop 209°C / B=#113: 26s dev, FC 4:10/206.3°C, drop 209°C / C=#114: 30s dev, FC 4:20/205.1°C, drop 206.3°C / D=#115: 35s dev, FC 4:04/203.5°C, drop 206°C", "expected_outcomes": "A: clean and bright, slight hollow risk. B: maximum clarity, underdevelopment risk. C: better internal development from longer mid-phase, dulling risk. D: best balance, integrated acidity, preserved clarity.", "failure_boundary": "Underdevelopment: hollow, thin body, sharp/disconnected acidity. Overdevelopment: muted florals, tea-like flattening, loss of lift. Profile mismatch: monotone cup, good structure but low character.", "observed_outcome_a": "Day 4: brightest and most expressive; fruity and clean; sour note emerges at cool; fermented fruit in full sip; carried to pourover. Pourover not completed — advanced #114 and #115 only.", "observed_outcome_b": "Day 4: clean but underdeveloped; flavors competing rather than integrating; sour-leaning attack; least resolved. Not carried to pourover.", "observed_outcome_c": "Day 4: least pleasant hot; disconnected attack; strongest temperature improvement trajectory; most complete at very cool stage. Pourover (Day 8): fermented funk absent — first clean expression in the run. Sweet, tropical fruit, vanilla, lemon-fruit acidity. Most characterful and attack-forward of the pair. Preferred when hot. Loses fruit/acidity in full cup as it cools; drying finish. Ground Agtron 72.3 vs WB 71.1 — even development confirmed.", "observed_outcome_d": "Day 4: most integrated hot; quieter on cool spoon; smooth and muted in full cup. Pourover (Day 8): fermented funk absent. More blended and rounded than #114; less attack; faint background fruit and vanilla. Slight flatness throughout but more consistent. Ground Agtron 75.6 vs WB 73.3 — small gap (2.3 pts), core slightly less developed than surface.", "winner": "#114 — preferred at pourover for expressiveness and character. #115 structurally sound but slightly flatter. Both confirmed clean — fermented character resolved.", "key_insight": "The fermented/funky character that appeared in V1–V4 cuppings is absent at Day 8 pourover for both #114 and #115. This confirms the issue was a roast artifact rather than a lot characteristic. Lowering drop temp to 206°C and targeting FC at 203–205°C resolved it. #114''s ground Agtron delta is negligible; #115 shows a small 2.3-point gap that may explain its relative flatness. The remaining issue is cup flattening and drying at cool stage in full cup.", "what_changes_going_forward": "Funk is resolved — V5 should not try to address fermented character. The new target is preserving the tropical fruit and vanilla complexity from #114 across the full temperature range, especially at cool stage in full cup. V5: fix charge at 117°C, target FC 200–202°C, test dev time as primary variable (35s/42s/50s). Measure ground Agtron at both Day 4 cupping and Day 10 pourover to track WB-to-ground delta as a development proxy."}, {"experiment_id": "SRUME-WASHED-COUNTERFLOW-04", "batch_ids": "118, 119, 120, 122", "context": "Fourth iteration. Goal was BBP correction to fix low TP and then test dev time. In practice the session became a charge temp and drop temp exploration — TP remained stubbornly low across all four roasts despite new BBP. Dev time varied as a consequence of changing charge temp and drop timing rather than as a controlled variable. Key discovery: charging at 117°C produced the best FC timing and phase structure (#122: FC 202.4°C at 3:53). Day 4 cupping completed 2026-03-30 at 4 days rest.", "primary_question": "With the BBP corrected for drum thermal stability, what development time produces the best balance of sweetness, body, and expressiveness without sacrificing the integration achieved in #115?", "control_baseline": "Batch #115 (FC 203.5°C, drop 206°C, 35s dev, 12.5% DTR, Agtron 73.3)", "shared_constants": "100g batch, Roest L200 Ultra, counterflow, RPM 65, inlet profile CF-Light (200→237→245→245→240→230→222°C), same coffee, new BBP", "variable_changed": "Charge temp and drop timing (dev time varied as consequence, not controlled variable)", "levels_tested": "A=#118: charge 112.2°C, FC 4:20/205.4°C, drop 207°C, 40s dev / B=#119: charge 113.3°C, FC 4:12/204.5°C, drop 206.3°C, 29s dev / C=#120: charge 119.3°C, FC 4:23/205.5°C, drop 206.4°C, 25s dev / D=#122: charge 117°C, FC 3:53/202.4°C, drop 206.7°C, 45s dev", "expected_outcomes": "A (#118): slow roast, risk of over-developed Maillard due to low charge and low TP. B (#119): cleaner structure from slightly higher charge, but dev time risk if drop timing too early. C (#120): higher charge should produce earlier FC and tighter Maillard — risk of very short dev time if not managed. D (#122): highest charge in session, expected earliest FC and most control over dev time.", "failure_boundary": "Underdevelopment: hollow body, thin mid-palate, sharp disconnected acidity, dev time below 12% DTR. Overdevelopment: muted florals, monotone cup, tea-like flattening, Agtron below 70. Total time under 4:30: drum over-corrected. Total time over 5:00: drum under-energized. Agtron above 78: verify internal development with ground Agtron at Day 10.", "observed_outcome_a": "Roast: darkest (Agtron 66.9), Maillard bloated 46.3%, total time at ceiling. Day 4: most aggressive and pungent; fermented charred pineapple on attack; very thin body; improves as it cools; at very cold stage sweetness dominates and fermented notes partially mask. Most characterful but least pleasant when hot.", "observed_outcome_b": "Roast: Agtron 73.5, drop 206.3°C, total 4:41, but dev only 29s/10.3%. Day 4: similar to #118 but rounded, less aggressive; star anise-like spice quality; slight improvement hot-to-cool on spoon; at very cold full cup stage sweetness surges — potentially second best expression at extreme cool.", "observed_outcome_c": "Roast: dev 8.7% below failure boundary, Maillard 49%. Day 4: least preferred at all stages — hollow, lactic fermented quality, elements separated and incoherent. Does not improve with cooling. Discard.", "observed_outcome_d": "Roast: lowest FC temp in run (202.4°C), DTR 16.2%, Maillard 40.3%, Agtron 77.8. Day 4: most complete and balanced at warm-to-cool stage; fruit integrated rather than aggressive; less pungent; sweetest in full cup; flaws emerge at very cold stage (roastier, harsher notes). Best overall at cupping temperature range but #118/#119 may be preferred at extreme cool.", "winner": "#122 at Day 4 cupping (warm-to-cool stage). #119 competitive at very cold stage. Both advance to Day 10 pourover.", "key_insight": "The fermented/funky character present across all four batches is unexpected for a washed coffee and appears to be either varietal character (Sudan Rume hybrid), a processing artifact from the hybrid washed method, or a residual roast artifact from high drop temps in prior sessions now expressing at Day 4. This should be cross-referenced with CGLE''s published tasting notes for this lot. #122''s lower FC temp (202.4°C) and Maillard (40.3%) produced the most integrated expression — confirming that FC temp and phase balance are the primary levers. Charge temp 117°C is now the established baseline.", "what_changes_going_forward": "Advance #122 and #119 to Day 10 pourover. V5 should fix charge at 117°C and run the planned dev time experiment (35s/40s/45s) cleanly. Check CGLE lot notes for expected flavor descriptors to distinguish varietal character from roast artifact. Add ground Agtron at Day 10 for #122."}, {"experiment_id": "SRUME-WASHED-COUNTERFLOW-05", "batch_ids": "133, 134, 135", "context": "Fifth iteration. Intended to isolate dev time with charge fixed at 117°C and CF-Light profile constant. Hopper pre-load timing emerged as an unplanned variable: #134 was loaded at ~125°C vs the standard ~120°C, producing FC at 197.6°C, the lowest in the run. Day 5 pourover completed April 8 and was tasted alongside recent #119 for direct comparison.", "primary_question": "With charge fixed at 117°C and CF-Light profile constant, what development time produces the cleanest expression of this coffee’s aromatic profile?", "control_baseline": "Batch #119 (FC 204.5°C, drop 206.3°C, 29s dev, Agtron 73.5, WB/ground delta 1.0 — pourover winner)", "shared_constants": "100g batch, Roest L200 Ultra, counterflow, RPM 65, CF-Light inlet profile, fan (80→70→65→72→75%), BBP-New, same coffee", "variable_changed": "Dev time end condition (A=0:45 / B=0:52 / C=1:00), with hopper pre-load timing as an unplanned additional variable", "levels_tested": "A=#133: 0:45 dev, standard hopper load ~120°C / B=#134: 0:52 dev, hopper loaded early ~125°C / C=#135: 1:00 dev, standard hopper load", "expected_outcomes": "A: #119 replica with better charge temp, FC ~202°C, tighter Maillard / B: extended dev adding sweetness and body / C: ceiling test", "failure_boundary": "Underdevelopment: hollow, nutty/grassy, DTR below 12% / Overdevelopment: muted florals, tea flattening, Agtron below 70, total time above 5:00 / WB-to-ground delta above 4 points: uneven development", "observed_outcome_a": "Roast: FC 4:07/204.5°C, drop 206.9°C, 34s/12.1%, Agtron 77.5, ground 74.6 (delta −2.9). Pourover: winner. Most character of the set despite being muted. Lemongrass, fruit, spice, herbal, cinnamon, sweetness in full cup. Clean. Feels under-extracted and likely needs brew adjustment.", "observed_outcome_b": "Roast: FC 3:32/197.6°C, drop 205.5°C, 50s/19.1%, Agtron 80.1, ground 80.5 (delta +0.4). Pourover: underdeveloped. Nutty, grassy, herbal, flat. Taster identified it immediately as the early-crack batch. WB and ground both very light, pointing to uniform underdevelopment rather than uneven development.", "observed_outcome_c": "Roast: FC 4:21/205.2°C, drop 206.7°C, 50s/16.1%, Agtron 69.1, ground 68.8 (delta −0.3). Pourover: overdeveloped. Dark black tea, flat, body-centric. Interesting cinnamon aroma at hot stage disappears in the cup.", "observed_outcome_d": null, "winner": "#133 — control batch confirmed as the best expression in V5 at pourover.", "key_insight": "The critical discovery is that this coffee has an FC floor: #134’s 197.6°C FC produced a uniformly underdeveloped cup despite long dev. Earlier/cooler FC is not automatically better. The usable FC window appears to be about 201–204°C, while 206–207°C begins to push overdevelopment.", "what_changes_going_forward": "V6 should revert to standard hopper load timing and focus on clean dev-time variation with FC staying in the 201–204°C range. Also test a pushed brew recipe on #133 before the next roast session to determine whether the remaining muting is a brew issue or a roast issue."}, {"experiment_id": "SRUME-WASHED-COUNTERFLOW-06", "batch_ids": "146, 147, 148", "context": "Sixth and final iteration. Goal was pure replication of Batch #133 (confirmed reference roast candidate via optimized pourover: candied apricot, bergamot, jasmine, florals, improves as it cools). No intentional variable changes — all three roasts attempted to replicate #133''s parameters exactly using CF-Light profile, standard hopper load at ~120°C, charge at 117°C, dev time 0:45 end condition, drop at 206–207°C. Replication proved moderately difficult — FC timing and Maillard phase varied slightly across session positions despite identical protocol.", "primary_question": "Can Batch #133''s roast parameters be replicated consistently across a session, and which of the three replication attempts best matches #133''s structural profile?", "control_baseline": "Batch #133 — FC 4:07/204.5°C, drop 206.9°C, dev 34s/12.1%, Maillard 44.8%, Agtron 77.5, ground 74.6, WB/ground delta −2.9. Confirmed reference via optimized brew (91°C, 1:14, EG-1 6.0): candied apricot, bergamot, jasmine, florals, improves as it cools.", "shared_constants": "100g batch, Roest L200 Ultra, counterflow, RPM 65, CF-Light inlet profile (200→237→245→245→240→230→222°C), fan (80→70→65→72→75%), BBP-New (100→60→40→25% fan, end 120°C), hopper load ~120°C, charge 117°C, dev time 0:45 end condition, same coffee", "variable_changed": "None intentional — session position (1st/2nd/3rd roast) varied naturally and produced measurable differences in FC timing and Maillard phase", "levels_tested": "A=#146: first roast in session, charge 116.2°C / B=#147: second roast, charge 116.3°C / C=#148: third roast, charge 115.6°C", "expected_outcomes": "All three to replicate #133: FC ~204–205°C at ~4:05–4:15, drop 206–207°C, dev ~34s/12%, Maillard ~44–45%, Agtron ~75–78", "failure_boundary": "FC above 206°C: profile running slow, insufficient drum energy. Drop above 208°C: overdevelopment risk. Maillard above 47%: Maillard bloat, insufficient early energy. DTR below 11%: underdevelopment. Agtron below 72 or above 80: outside target range.", "observed_outcome_a": "FC 4:19/205.7°C, drop 206.9°C, dev 32s/11.0%, Maillard 47.8%, Agtron 74.8. First roast in session — drum slightly less energized despite same charge target. FC arrived ~12 seconds later and ~1.2°C hotter than #133. Maillard slightly bloated at 47.8%. Drop temp excellent. DTR marginally below target.", "observed_outcome_b": "FC 4:17/205.0°C, drop 206.5°C, dev 36s/12.3%, Maillard 46.4%, Agtron 75.9. Second roast — sequential drum heat improved FC timing marginally. DTR closest to #133 at 12.3%. Drop temp excellent. Still ~10 seconds late on FC vs #133.", "observed_outcome_c": "FC 4:09/204.4°C, drop 206.6°C, dev 38s/13.2%, Maillard 44.6%, Agtron 75.5. Third roast — sequential heat advantage most visible. FC timing (4:09) and temp (204.4°C) closest to #133 of all three. Maillard 44.6% essentially identical to #133''s 44.8%. Best structural match of the session.", "observed_outcome_d": "#148 — closest structural match to #133 across all key metrics", "winner": "Replication is meaningfully affected by session position even with identical protocol. First roast in a session consistently runs slightly slower and hotter through Maillard than second or third roast despite same charge temp trigger. The drum accumulates residual heat across sequential roasts that improves FC timing even when the logged charge temp reads the same. For a coffee where FC timing is the primary lever, this means the first roast of any session will be the hardest to replicate precisely — consider treating it as a warm-up roast or accepting it will run slightly slower. #148 being the closest match to #133 suggests that by the third roast, drum thermal state has fully stabilized into a repeatable zone.", "key_insight": "Lot is now resolved — declare #133 as reference roast (first confirmed, best documented). #148 is the closest replication and could serve as a secondary confirmation. Advance all three to Day 7 pourover using optimized brew recipe (91°C, 1:14, EG-1 6.0) to confirm cup quality matches #133. If #148 confirms, close lot formally. Document session position effect as a generalizable counterflow learning: for sensitive coffees where FC timing is the primary lever, first roast of session may need a slightly earlier hopper load (~125°C) to compensate for lower residual drum heat, while second and third roasts can use standard ~120°C load.", "what_changes_going_forward": null}]') AS rec(
    experiment_id text, batch_ids text, context text, primary_question text,
    control_baseline text, shared_constants text, variable_changed text,
    levels_tested text, expected_outcomes text, failure_boundary text,
    observed_outcome_a text, observed_outcome_b text, observed_outcome_c text,
    observed_outcome_d text, winner text, key_insight text, what_changes_going_forward text
  )
ON CONFLICT (user_id, green_bean_id, experiment_id) DO NOTHING;

-- =====================================================================
-- Cuppings (27 rows)
--   * brew_method folded into eval_method at import (schema gap - no brew_method column)
--   * sweetness dropped entirely (schema gap - no sweetness column)
-- =====================================================================
WITH bean AS (SELECT id AS green_bean_id, user_id FROM green_beans WHERE lot_id = 'CGLE-SRUME-WASHED-2026')
INSERT INTO cuppings (
  user_id, roast_id,
  cupping_date, rest_days, eval_method, ground_agtron, ground_color_description,
  aroma, flavor, acidity, body, finish, overall
)
SELECT
  bean.user_id,
  (SELECT id FROM roasts WHERE user_id = bean.user_id AND green_bean_id = bean.green_bean_id AND batch_id = rec.batch_id),
  rec.cupping_date::date, rec.rest_days, rec.eval_method, rec.ground_agtron,
  rec.ground_color_description, rec.aroma, rec.flavor, rec.acidity,
  rec.body, rec.finish, rec.overall
FROM bean,
  jsonb_to_recordset('[{"batch_id": "104", "cupping_date": "2026-03-23", "rest_days": 3, "eval_method": "Comparative cupping - Cupping", "ground_agtron": null, "ground_color_description": null, "aroma": "Fruity, acidic, clean, no roast character", "flavor": "Very sweet, juicy, fruit-driven", "acidity": "Bright but somewhat disconnected", "body": "Thin, hollow, lacking structure", "finish": "Clean but slightly empty", "overall": "Highly expressive but structurally incomplete; strong aromatics and sweetness but lacks mid-palate integration"}, {"batch_id": "106", "cupping_date": "2026-03-23", "rest_days": 3, "eval_method": "Comparative cupping - Cupping", "ground_agtron": null, "ground_color_description": null, "aroma": "Similar to 104 but more intense", "flavor": "More complete, still fruit-forward but less expressive in full sip", "acidity": "Bright, slightly better integrated but still somewhat disconnected", "body": "Slightly fuller than 104 but still a bit hollow", "finish": "Clean, slightly more integrated", "overall": "Improved over 104 but still not fully integrated; becomes somewhat monotone and less expressive when drinking"}, {"batch_id": "108", "cupping_date": "2026-03-23", "rest_days": 3, "eval_method": "Comparative cupping - Cupping", "ground_agtron": null, "ground_color_description": null, "aroma": "Most intense aromatics, similar profile", "flavor": "More pleasant, more integrated, slightly flatter profile", "acidity": "Strong acidity, more integrated into structure", "body": "Fuller and more cohesive than 104/106", "finish": "Clean but slightly flattened", "overall": "Most complete and drinkable, but loses distinctiveness; more monotone and less character-driven than 104"}, {"batch_id": "109", "cupping_date": "2026-03-25", "rest_days": 3, "eval_method": "Cupping (spoon + full bowl sip) - Cupping", "ground_agtron": null, "ground_color_description": null, "aroma": "Sweet, slightly nutty, underdeveloped smell", "flavor": "High acidity, juicy, bright but aggressive, incomplete", "acidity": "Very bright, aggressive, almost sour at full sip", "body": "Tea-like, feels incomplete", "finish": "Disconnected, acidity turning sour in full sip", "overall": "Unbalanced, disconnected acidity and body, underdeveloped tinge in full sip"}, {"batch_id": "110", "cupping_date": "2026-03-25", "rest_days": 3, "eval_method": "Cupping (spoon + full bowl sip) - Cupping", "ground_agtron": null, "ground_color_description": null, "aroma": "Fuller, spicier, no underdeveloped nutty note", "flavor": "Similar to #109 but slightly more integrated; bright attack, lime acidity, little sweetness", "acidity": "Aggressive, bright, lime character, persistent", "body": "Tea-like, darker/browner tea variety", "finish": "Small bitterness at end, more complete", "overall": "Most complete and integrated of the set; loses expressiveness, becoming monotone"}, {"batch_id": "111", "cupping_date": "2026-03-25", "rest_days": 3, "eval_method": "Cupping (spoon + full bowl sip) - Cupping", "ground_agtron": null, "ground_color_description": null, "aroma": "Underdeveloped smell, similar to #109", "flavor": "Flat, less aggressive than #109, trending monotone, less expressive", "acidity": "Present but muted, lacks aggressiveness", "body": "Light, flat", "finish": "Not described", "overall": "Flat throughout; not expressive, not sweet, not roasty — just flat; more pleasant as full sip than #109 but less character than #110"}, {"batch_id": "112", "cupping_date": "2026-03-26", "rest_days": 3, "eval_method": "Cupping (spoon + full bowl sip) - Cupping", "ground_agtron": null, "ground_color_description": null, "aroma": "Fruity, sweet, no roast signature", "flavor": "Juicy, light, sweet, very crisp; bright and fruity as it cools; slight sour note when cool", "acidity": "Very bright, fruity, slight sour note when cool; most acidic of the set in full sip", "body": "Very thin, very light", "finish": "No roast aftertaste, very clean", "overall": "Brightest, most expressive of the set; slightly fermented fruit quality in full sip; lightest expression overall; carried forward to pourover"}, {"batch_id": "113", "cupping_date": "2026-03-26", "rest_days": 3, "eval_method": "Cupping (spoon + full bowl sip) - Cupping", "ground_agtron": null, "ground_color_description": null, "aroma": "Similar to #112, slightly bolder, slight tea note", "flavor": "Attack more prominent, drifting sour; slightly darker/more developed expression than #112; flavors competing, less blended in full sip", "acidity": "Bright, sour-leaning attack; more acidity than #114/#115", "body": "Very light, tea-like", "finish": null, "overall": "Clean but less integrated; flavors present but competing; slightly sour; likely underdeveloped; not carried forward"}, {"batch_id": "114", "cupping_date": "2026-03-26", "rest_days": 3, "eval_method": "Cupping (spoon + full bowl sip) - Cupping", "ground_agtron": null, "ground_color_description": null, "aroma": "Flatter than #112 and #113", "flavor": "Disconnected attack from body when hot; more complete and integrated when cool; some juiciness, sweetness, tea-like; slight sour note in full sip (less prominent very cool)", "acidity": "Disconnected acidity when hot; integrates better when cool", "body": "Tea-like; feels more complete at cooler temps", "finish": null, "overall": "Less pleasant hot; becomes most complete of the set when cool and very cool; slight sour note in full sip fades at lower temp; carried forward to pourover"}, {"batch_id": "115", "cupping_date": "2026-03-26", "rest_days": 3, "eval_method": "Cupping (spoon + full bowl sip) - Cupping", "ground_agtron": null, "ground_color_description": null, "aroma": "Mix of sweetness, tea, development — most complete aroma", "flavor": "More integrated and blended when hot; quieter/flatter on spoon when cool; full sip reveals sweetness, juiciness, fruitiness — muted but present and smooth", "acidity": "Less prominent acidity; more blended; not sharp", "body": "Light; smooth; no roast character", "finish": "No roast signature, no bitterness", "overall": "Most integrated hot; flatter/quieter on cool spoon; full sip reveals pleasant smooth cup with muted fruit; preferred alongside #114; carried forward to pourover"}, {"batch_id": "106", "cupping_date": "2026-03-29", "rest_days": 9, "eval_method": "Pourover, spoon + full cup sip - xbloom (Brian Quan profile)", "ground_agtron": 74.0, "ground_color_description": "Light", "aroma": "Sweet, nutty", "flavor": "Sharper acidity on attack with slight fermented/sour fruit quality; tropical fruit at cooler temp; transition into body present; some sweetness", "acidity": "Bright, sharp on attack; sour-leaning fruit quality; not a clean juicy acidity", "body": "Black tea; darker black tea expression at cooler temp", "finish": "Drying, oversteeped quality; pungent", "overall": "Clear preference over #108. Brighter, lighter, fruitier. More expressive. Tropical quality emerges as it cools. Some drying/oversteep present but much less than #108. Night-and-day difference in full cup vs #108."}, {"batch_id": "108", "cupping_date": "2026-03-29", "rest_days": 9, "eval_method": "Pourover, spoon + full cup sip - xbloom (Brian Quan profile)", "ground_agtron": 70.8, "ground_color_description": "Medium-light", "aroma": "Nutty, spicy — less sweet than #106", "flavor": "Less pleasant attack; body-centric; nutty with slight sour-fruity; darker, heavier overall", "acidity": "Lower acidity than #106; background sourness rather than attack", "body": "Darker, heavier black tea; fuller than #106 but less pleasant", "finish": "More drying and bitter than #106; orange rind quality; pronounced oversteep feeling", "overall": "Darker, heavier, less expressive. No real attack. Body-centric. Orange rind, bitter aftertaste, pronounced drying and oversteep character. Not bad but a very different and less interesting expression."}, {"batch_id": "118", "cupping_date": "2026-03-30", "rest_days": 4, "eval_method": "Cupping, spoon + full cup sip - Cupping", "ground_agtron": null, "ground_color_description": null, "aroma": "Pungent fruit", "flavor": "Fermented tropical fruit — “fermented charred pineapple”; very frontal and forward; aggressive; tea-like body at back end", "acidity": "Aggressive, pungent, fermented-fruit acidity", "body": "Thin; tea-like at back end", "finish": "Bitter note; pungent; tea lingers", "overall": "Most extreme and aggressive; very interesting but not necessarily pleasant; most characterful; pungent; best if you want maximum expressiveness; preference shifts over temperature — better very cool in full cup"}, {"batch_id": "119", "cupping_date": "2026-03-30", "rest_days": 4, "eval_method": "Cupping, spoon + full cup sip - Cupping", "ground_agtron": null, "ground_color_description": null, "aroma": "Similar to #118, plus interesting spiciness", "flavor": "Similar profile to #118 but more tamped down; less aggressive; caramel/fermented pineapple quality; spice note (star anise-like, non-licorice)", "acidity": "Similar but rounded; less aggressive", "body": "Slightly disconnected from attack; tea-like", "finish": "Less pungent than #118", "overall": "Middle ground — less aggressive than #118, more expressive than #122; spice quality interesting; preference shifted upward at very cool full cup stage; may be second choice"}, {"batch_id": "120", "cupping_date": "2026-03-30", "rest_days": 4, "eval_method": "Cupping, spoon + full cup sip - Cupping", "ground_agtron": null, "ground_color_description": null, "aroma": "Similar to #119, slightly quieter volume", "flavor": "Similar profile but hollow; feels out of place; lactic fermented quality; elements feel separated", "acidity": "Hollow; out of place", "body": "Hollow; thin", "finish": null, "overall": "Least preferred at all stages — hollow, lactic, separated; elements don''t cohere"}, {"batch_id": "122", "cupping_date": "2026-03-30", "rest_days": 4, "eval_method": "Cupping, spoon + full cup sip - Cupping", "ground_agtron": null, "ground_color_description": null, "aroma": "Less fruit than others, more spice", "flavor": "Fermented pineapple quality but on back end of body rather than attack; barbecued/cooked quality; most complete and balanced; less pungent; tea-like at back end; slight lactic note present", "acidity": "Less forward; blended in", "body": "More complete; tea-like but better integrated", "finish": "Slight lactic/fermented note; roastier at very cool stage", "overall": "Most complete, most balanced, least aggressive; fruit present but integrated; preference at warm-to-cool stage; flaws emerge at very cold stage (roastier, harsher notes); overall winner but with caveats"}, {"batch_id": "114", "cupping_date": "2026-03-31", "rest_days": 8, "eval_method": "Pourover — spoon + full cup sip - xbloom (Brian Quan profile)", "ground_agtron": 72.3, "ground_color_description": "Light", "aroma": "Woody, earthy tea with some sweetness", "flavor": "Sweet, fruity, tropical (not fermented); vanilla; pleasant; acidity accentuated when cool (lemon-fruit); more body-centric in full cup", "acidity": "Bright when hot; lemon-fruit quality when cool; accentuated at cool stage on spoon", "body": "Brown tea; slightly heavy", "finish": "Drying note; slight bitterness in full cup; flattens as it cools", "overall": "Preferred at hot stage — sweet, fruity, tropical, vanilla, no funk. Becomes more body-centric and loses some fruit character as it cools in full cup. Drying finish is the primary downside. More characterful than #115 with more attack."}, {"batch_id": "115", "cupping_date": "2026-03-31", "rest_days": 8, "eval_method": "Pourover — spoon + full cup sip - xbloom (Brian Quan profile)", "ground_agtron": 75.6, "ground_color_description": "Light", "aroma": "Sweet brown tea — slightly less earthy, slightly more sweet than #114", "flavor": "Similar to #114 but less attack, less sweetness, more blended together; more tea-forward; faint background fruit and vanilla present", "acidity": "Less accentuated than #114; more blended in", "body": "Tea-forward; slightly flatter than #114", "finish": "Drying note; flattening at cool stage; faint sweetness lingers", "overall": "Slightly more blended and rounded than #114; less attack; more flat overall but has a faint background sweetness and fruit that persists. Feels like more is there underneath but it doesn''t fully express. Slight flatness. Preferred at cool stage by a narrow margin due to underlying sweetness."}, {"batch_id": "110", "cupping_date": "2026-04-01", "rest_days": 10, "eval_method": "Pourover — spoon + full cup sip - xbloom (Brian Quan profile)", "ground_agtron": 70.8, "ground_color_description": "Medium light", "aroma": "Fruity, creamy, interesting spice element", "flavor": "No real fruit or attack; tea, spice, cardamom/Christmas spice body when hot; mellows and flattens when cool; lactic/cheese-like quality emerges in full cup sip", "acidity": "Low; not a primary characteristic at any stage", "body": "Tea, spice — interesting when hot; loses character in full cup", "finish": "Unpleasant in full cup — lactic, cheese-like quality dominates and overrides spice/body character", "overall": "Preferred on hot spoon for spice/tea character. Full cup reveals lactic/cheese defect that undermines the expression significantly. Not preferred in full cup."}, {"batch_id": "111", "cupping_date": "2026-04-01", "rest_days": 10, "eval_method": "Pourover — spoon + full cup sip - xbloom (Brian Quan profile)", "ground_agtron": 73.5, "ground_color_description": "Light", "aroma": "Same general profile as #110, more spice, less fruit", "flavor": "More pungent spice when hot; mellows more than #110 as it cools; more sweetness at cool stage; full cup: sweetness, tea, vanilla, light tropical fruit (raspberry noted); smooth; clean aftertaste; no spice in full sip", "acidity": "Low; not forward; smooth", "body": "Medium-light brown tea; smooth in full cup", "finish": "Clean aftertaste; pleasant; no lactic note", "overall": "Less characterful than #110 on hot spoon. Full cup and cool stage reveal a more pleasant, smooth, integrated cup — sweetness, vanilla, light tropical fruit, clean finish. Preferred in full cup and at cool stage."}, {"batch_id": "118", "cupping_date": "2026-04-02", "rest_days": 7, "eval_method": "Pourover — full cup sip only (new protocol) - xbloom (Brian Quan profile)", "ground_agtron": 71.2, "ground_color_description": "Light", "aroma": "Fruity, light spice — pleasant", "flavor": "Fruit and sweetness on entry, no pungent attack; darker tea body with cardamom/spice/vanilla notes; a lot happening; tart quality separates slightly from body as it cools", "acidity": "Tart quality separates from body at cooler temp", "body": "Darker tea; spice-weighted", "finish": "Spice lingers; sits on tongue; slightly heavy", "overall": "Good character and spice complexity; tart element separates slightly as it cools; third or fourth preference"}, {"batch_id": "119", "cupping_date": "2026-04-02", "rest_days": 7, "eval_method": "Pourover — full cup sip only - xbloom (Brian Quan profile)", "ground_agtron": 74.5, "ground_color_description": "Light", "aroma": "Similar to #118, slightly more intense", "flavor": "Fruit and sweet entry into tea body; spice notes present but more blended and integrated than #118; slightly louder intensity than #118; tart quality emerges as it cools; jasmine-like sweetness noted; fruit forward", "acidity": "Fruit-acidic, tart quality at cooler temp; more fruit-forward than #122", "body": "Tea-like; blended", "finish": null, "overall": "Preferred by both tasters; sweet-fruit forward, jasmine-like, most expressive; tart quality is present but as fruit acidity rather than separation; second taster (Kim) also chose this"}, {"batch_id": "120", "cupping_date": "2026-04-02", "rest_days": 7, "eval_method": "Pourover — full cup sip only - xbloom (Brian Quan profile)", "ground_agtron": 73.7, "ground_color_description": "Light", "aroma": "Similar to #119, slightly more fruit-sweet", "flavor": "Most integrated and blended of the set; sweet, spice notes well integrated; rounded; lacks some punch and character compared to #122", "acidity": "Most integrated acidity; least separation", "body": "Tea-like; most integrated body", "finish": null, "overall": "Most integrated and round; most transparent; pleasant but lacks character and punch; good if you want balance over expressiveness"}, {"batch_id": "122", "cupping_date": "2026-04-02", "rest_days": 7, "eval_method": "Pourover — full cup sip only - xbloom (Brian Quan profile)", "ground_agtron": 75.2, "ground_color_description": "Light", "aroma": "Sweet, slightly more fruit complexity than #120", "flavor": "Smooth; tart quality present but gives complexity and character; more body-centric than #119; more complexity than #120; slightly less fruit-forward than #119", "acidity": "Tart quality present, adds complexity; more integrated than #118", "body": "Tea-like; body-centric with complexity", "finish": null, "overall": "Most complex; tart element adds character; more body-centric; close second to #119; more interesting than #120 but slightly less expressive than #119"}, {"batch_id": "133", "cupping_date": "2026-04-08", "rest_days": 5, "eval_method": "Pourover — spoon + full cup sip - xbloom (Brian Quan recipe)", "ground_agtron": 74.6, "ground_color_description": "Light", "aroma": "Sweet, herbal, light tea, earthy", "flavor": "Not much attack; sweetness, tea, herbal/cinnamon spice in body and aftertaste; lemongrass fruit and spice in full cup; most pleasant flavors of the set but muted/hidden; needs more extraction", "acidity": "Underlying sweetness-acidity at cool stage; present but hidden", "body": "Medium — “wants to be extracted more”; thin on attack, more medium weight in body", "finish": "Herbal, spice, cinnamon — interesting", "overall": "Winner. Most character of the set despite being muted. Lemongrass, fruit, spice, sweetness in full cup. Clean. Feels under-extracted — brew recipe adjustment likely needed rather than roast change. Control batch confirmed as best structural expression."}, {"batch_id": "134", "cupping_date": "2026-04-08", "rest_days": 5, "eval_method": "Pourover — spoon + full cup sip - xbloom (Brian Quan recipe)", "ground_agtron": 80.5, "ground_color_description": "Light — notably lighter than WB reading", "aroma": "Nutty, spicy", "flavor": "Nutty, grassy, herbal; underdeveloped character; more flat as it cools", "acidity": "Low", "body": "Flat; loses what little character it had as it cools", "finish": "Flat", "overall": "Underdeveloped — taster correctly identifies by taste alone as the early-crack batch. Nutty, grassy, herbal. Loses character as it cools. Not the advancement hoped for structurally."}, {"batch_id": "135", "cupping_date": "2026-04-08", "rest_days": 5, "eval_method": "Pourover — spoon + full cup sip - xbloom (Brian Quan recipe)", "ground_agtron": 68.8, "ground_color_description": "Medium-light", "aroma": "Cinnamon, almost cinnamony — most distinct aroma of the set", "flavor": "Dark black tea dominant; cinnamon and spice at hot stage lose character as it cools; flat; overdeveloped", "acidity": "Low", "body": "Body-centric but flat; darker expression without interest", "finish": "Flat; lost cinnamon character from hot stage", "overall": "Overdeveloped — darker, flatter, body-centric. Lost the interesting cinnamon/spice character from hot stage. Confirms 1:00 dev end condition and sequential drum heat combination pushed too far."}]') AS rec(
    batch_id text, cupping_date text, rest_days integer, eval_method text,
    ground_agtron numeric, ground_color_description text, aroma text, flavor text,
    acidity text, body text, finish text, overall text
  )
ON CONFLICT (user_id, roast_id, cupping_date, eval_method) DO NOTHING;

-- =====================================================================
-- Roast learnings (1 row)
-- =====================================================================
WITH bean AS (SELECT id AS green_bean_id, user_id FROM green_beans WHERE lot_id = 'CGLE-SRUME-WASHED-2026')
INSERT INTO roast_learnings (
  user_id, green_bean_id,
  best_batch_id, why_this_roast_won, aromatic_behavior, structural_behavior,
  elasticity, roast_window_width, primary_lever, secondary_levers,
  what_didnt_move_needle, underdevelopment_signal, overdevelopment_signal,
  cultivar_takeaway, general_takeaway, reference_roasts, starting_hypothesis,
  rest_behavior
)
SELECT
  bean.user_id, bean.green_bean_id,
  rec.best_batch_id, rec.why_this_roast_won, rec.aromatic_behavior, rec.structural_behavior,
  rec.elasticity, rec.roast_window_width, rec.primary_lever, rec.secondary_levers,
  rec.what_didnt_move_needle, rec.underdevelopment_signal, rec.overdevelopment_signal,
  rec.cultivar_takeaway, rec.general_takeaway, rec.reference_roasts, rec.starting_hypothesis,
  rec.rest_behavior
FROM bean,
  jsonb_to_recordset('[{"best_batch_id": "133", "why_this_roast_won": "#133 achieved the right combination of FC temp (204.5°C), drop temp (206.9°C), and Maillard phase balance (44.8%) that allowed the coffee''s core aromatic character to express cleanly in an optimized pourover. The WB-to-ground Agtron delta was tight (−2.9), confirming even internal development. At the optimized brew recipe (91°C, 1:14, EG-1 6.0, Melodrip), the cup produced candied apricot, bergamot, jasmine, and floral character that matched the producer''s own tasting notes and improved meaningfully as it cooled — the defining signal of a well-resolved roast.", "aromatic_behavior": "Primary aromatics: jasmine, floral, bergamot, candied apricot. Secondary: faint herbal/mint note at finish consistent with the producer''s \"fresh mint / brown spices\" descriptors. Aromatics are delicate and do not appear fully at standard extraction — they require a pushed brew recipe (lower temp, higher concentration, finer grind) to express fully. At standard pourover parameters the cup reads muted and tea-like, which can be mistaken for a roast deficiency. The aromatics are present in the roast but need unlocking at brew.", "structural_behavior": "Light tea body throughout — this is a characteristic of the variety and process, not a failure signal. Body does not become heavy or syrupy as development increases. The coffee has a clean, delicate structure that rewards patience: it flattens if you rush extraction (high temp, coarse grind) and opens if you slow down (lower temp, finer grind, higher concentration). Full cup sip consistently revealed more character than spoon throughout the experiment run, suggesting the coffee benefits from sustained extraction contact time.", "elasticity": "High elasticity at the right roast. The coffee responded strongly to brew recipe changes — the delta between standard xbloom recipe and optimized 91°C/1:14 recipe was dramatic (muted tea vs. candied apricot/bergamot). It improves consistently as the cup cools, revealing more sweetness and complexity at 45–50°C than at 60°C. This makes it a genuinely elastic roast — you can choose how aggressively to brew it and it responds rather than collapsing.", "roast_window_width": "Narrow. FC temp window: approximately 201–205°C. Below 200°C (#134 at 197.6°C) produces uniform underdevelopment — nutty, grassy, flat regardless of dev time. Above 206°C (#118, #135) produces overdevelopment — dark tea, flat, loss of top-note lift. Drop temp window: 205–207°C. Below 205°C risks underdevelopment at the finish; above 208°C begins to suppress jasmine and floral character. The usable roast window is approximately 4°C wide at FC temp and 2°C wide at drop temp — this is a demanding coffee that requires precision.", "primary_lever": "FC temp and drop temp working together. Getting FC to arrive in the 202–205°C range at ~4:05–4:15 and dropping at 206–207°C was the decisive variable across the entire experiment run. Every session where these two numbers were in range produced a viable cup. Every session where either was out of range produced a defective or uninteresting one. Profile shape (CF-Light) and dev time were secondary once these two anchors were established.", "secondary_levers": "WB-to-ground Agtron delta as an internal development signal. Tight delta (≤3 points) correlated with the best cup quality. Batches with large deltas (e.g. #118 at +4.3) produced cups where surface and core development were uneven, resulting in tart separation or flat body. Brew recipe temperature (91°C vs 94°C) was a significant secondary lever at the cup level — a 3°C reduction unlocked the delicate aromatics that higher temp extraction was blunting.", "what_didnt_move_needle": "TP (turning point temperature) — remained at 78–81°C across the entire experiment run regardless of charge temp, BBP fan curve, or hopper timing. Investigated extensively but never resolved. TP appears to be a machine-specific measurement artifact on this Roest unit and should not be used as a diagnostic signal. FC temp and FC timing are more reliable drum-state proxies. Extended dev time beyond 45s — tested up to 50–60s and did not improve the cup; the coffee''s development is constrained by its narrow drop temp window rather than dev time length. Going beyond 45s simply pushed the drop temp over the ceiling.", "underdevelopment_signal": "Cup reads nutty, grassy, or herbal with flat body and no aromatic lift. FC below 200°C is the roast-level signal. WB Agtron above 79 combined with ground Agtron above 78 (both very light) indicates uniform underdevelopment throughout the bean. Batch #134 (FC 197.6°C, Agtron 80.1, ground 80.5) is the reference example.", "overdevelopment_signal": "Cup reads dark black tea, flat, body-centric with loss of jasmine and floral character. Drop temp above 208°C is the primary roast-level signal. Maillard above 47% is a correlated warning sign. Agtron below 71 at WB indicates the surface has pushed too far. Batches #108 (drop 214.6°C) and #135 (Maillard 44.7%, total time 5:11) are the reference examples.", "cultivar_takeaway": "Sudan Rume as a variety produces unusually delicate, high-compound aromatics — jasmine, bergamot, floral, stone fruit — that are easily suppressed by overdevelopment and easily missed by under-extraction at brew. The \"lemongrass/herbal\" character that appeared throughout the experiment run (and confused descriptor naming) is consistent with this variety''s unusual aromatic compounds, which also express in the Natural version of the same coffee. The aromatics are present at a wider range of roast levels than they appear — the problem was consistently brew extraction, not roast absence. Sudan Rume is one of the most demanding coffees to fully express in both roast and brew.", "general_takeaway": "For dense, high-quality washed Colombians with unusual aromatic compounds: solve FC temp first (profile shape), then solve drop temp discipline (drop on temp not clock), then solve brew recipe (lower temp, higher concentration than standard). Do not chase higher drop temps to add body — body in this style of coffee comes from even internal development, not from pushing the end temp. The cupping table is an unreliable decision gate for this type of coffee — Day 4 results were misleading in multiple directions throughout this experiment. Pourover at Day 7+ with an optimized recipe is the only reliable evaluation method.", "reference_roasts": "Friend''s Batch #249 (\"IT simple slow 100g\") — washed Sudan Rume on same machine, FC 200.3°C, drop 205°C, dev 36s/13.3%, Maillard 39.1%. Used as structural benchmark throughout. Closer than initially appeared once charge temp and hopper timing were corrected. Special Guests (London) roast of the Sudan Rume Natural — tasted directly, confirmed lemongrass/ginger/bergamot character as the correct aromatic target for this variety.", "starting_hypothesis": "For other high-density washed Colombians with unusual floral/citrus aromatics: start with CF-Light profile (200→237→245→245→240→230→222°C), target FC at 202–205°C, drop at 206–207°C. Expect the aromatics to be hidden at standard brew parameters — always test with a pushed recipe (91°C, 1:14, fine grind) before concluding the roast is under-expressing. WB-to-ground Agtron delta is the most reliable internal development signal — target ≤3 points. Budget for 4–6 experiment sessions to resolve a coffee in this flavor category.", "rest_behavior": "Day 7 pourover is the correct evaluation gate for this coffee. Day 4 cupping was consistently misleading — batches that looked underdeveloped at Day 4 revealed complexity at Day 7 (most dramatically: #111 reversed completely from flat to vanilla-fruit-raspberry between Day 4 and Day 10). Day 5 pourover is slightly too early — #133 tasted at Day 5 read muted and under-extracted; the same batch at Day 6–7 with optimized recipe produced the reference cup. The coffee continues to open between Day 7 and Day 10 but the directional signal at Day 7 is reliable. Rest in foil bags with degassing valve — sandwich bags are insufficient for 7-day rest on this style of roast."}]') AS rec(
    best_batch_id text, why_this_roast_won text, aromatic_behavior text,
    structural_behavior text, elasticity text, roast_window_width text,
    primary_lever text, secondary_levers text, what_didnt_move_needle text,
    underdevelopment_signal text, overdevelopment_signal text, cultivar_takeaway text,
    general_takeaway text, reference_roasts text, starting_hypothesis text,
    rest_behavior text
  )
ON CONFLICT (user_id, green_bean_id) DO NOTHING;

COMMIT;
